import React, { useState, useEffect } from 'react';
import { Link, useNavigate } from 'react-router-dom';
import { useAuth } from '../context/AuthContext';
import { useTheme } from '../context/ThemeContext';
import axios from 'axios';

export default function StudentDashboard() {
  const { user, API } = useAuth();
  const { dark } = useTheme();
  const navigate = useNavigate();
  const [projects, setProjects]   = useState([]);
  const [requests, setRequests]   = useState([]);
  const [notifs, setNotifs]       = useState([]);
  const [loading, setLoading]     = useState(true);

  const bg    = dark ? '#0a0d14' : '#f4f6fb';
  const card  = dark ? '#161c2e' : '#ffffff';
  const border= dark ? '#252d47' : '#e2e8f0';
  const text  = dark ? '#e8eaf0' : '#1a1a2e';
  const muted = dark ? '#9aa3bf' : '#64748b';
  const sub   = dark ? '#5c6580' : '#94a3b8';

  useEffect(() => {
    const load = async () => {
      const h = { headers:{Authorization:`Bearer ${localStorage.getItem('token')}`}, timeout:15000 };
      try {
        const [pRes, rRes, nRes] = await Promise.all([
          axios.get(`${API}/projects?status=open`, h),
          axios.get(`${API}/requests/my`, h),
          axios.get(`${API}/notifications`, h),
        ]);
        const calcMatch = (skills) => {
          if (!user.skills?.length || !skills?.length) return 0;
          const s = user.skills.map(x=>x.toLowerCase());
          const r = skills.map(x=>x.toLowerCase());
          return Math.round((r.filter(sk=>s.some(ss=>ss.includes(sk)||sk.includes(ss))).length/r.length)*100);
        };
        setProjects([...pRes.data].map(p=>({...p,match:calcMatch(p.requiredSkills)})).sort((a,b)=>b.match-a.match).slice(0,3));
        setRequests(rRes.data);
        setNotifs(nRes.data.filter(n=>!n.read).slice(0,3));
      } catch {}
      setLoading(false);
    };
    load();
  }, [API]);

  const accepted = requests.filter(r=>r.status==='accepted');
  const pending  = requests.filter(r=>r.status==='pending');

  if (loading) return <div style={{display:'flex',alignItems:'center',justifyContent:'center',height:'60vh',color:'#6c63ff',fontSize:'1rem'}}>Loading...</div>;

  return (
    <div style={{minHeight:'100vh',background:bg,padding:'1.5rem',fontFamily:'system-ui,sans-serif'}}>
      <div style={{maxWidth:960,margin:'0 auto'}}>

        {/* Top greeting */}
        <div style={{marginBottom:'1.5rem'}}>
          <h1 style={{fontWeight:800,fontSize:'1.4rem',color:text,marginBottom:'0.2rem'}}>Hi, {user.name.split(' ')[0]} 👋</h1>
          <p style={{color:muted,fontSize:'0.85rem'}}>{user.department} · {user.year}</p>
        </div>

        {/* Unread Alerts — only if any */}
        {notifs.length > 0 && (
          <div style={{marginBottom:'1.5rem'}}>
            {notifs.map(n=>(
              <div key={n._id} onClick={()=>navigate('/notifications')} style={{background:dark?'rgba(108,99,255,0.08)':'#f0eeff',border:`1px solid ${dark?'#6c63ff30':'#c4bbff'}`,borderRadius:10,padding:'0.75rem 1rem',marginBottom:'0.5rem',cursor:'pointer',display:'flex',alignItems:'center',gap:'0.75rem'}}>
                <span style={{fontSize:'1rem'}}>🔔</span>
                <span style={{fontSize:'0.85rem',color:text,flex:1}}>{n.message}</span>
                <span style={{fontSize:'0.7rem',color:sub}}>new</span>
              </div>
            ))}
            <Link to="/notifications" style={{fontSize:'0.8rem',color:'#6c63ff',fontWeight:600,textDecoration:'none'}}>View all notifications →</Link>
          </div>
        )}

        {/* Stats row */}
        <div style={{display:'grid',gridTemplateColumns:'repeat(4,1fr)',gap:'0.75rem',marginBottom:'1.5rem'}}>
          {[
            {label:'Applied',  value:requests.length, color:'#6c63ff', link:'/requests'},
            {label:'Accepted', value:accepted.length, color:'#22c55e', link:'/requests'},
            {label:'Pending',  value:pending.length,  color:'#f59e0b', link:'/requests'},
            {label:'Projects', value:projects.length, color:'#00d4aa', link:'/projects'},
          ].map((s,i)=>(
            <div key={i} onClick={()=>navigate(s.link)} style={{background:card,border:`1px solid ${border}`,borderRadius:12,padding:'1rem',cursor:'pointer',textAlign:'center'}}>
              <div style={{fontSize:'1.6rem',fontWeight:800,color:s.color,lineHeight:1}}>{s.value}</div>
              <div style={{fontSize:'0.75rem',color:muted,marginTop:'0.3rem'}}>{s.label}</div>
            </div>
          ))}
        </div>

        <div style={{display:'grid',gridTemplateColumns:'1.5fr 1fr',gap:'1rem'}}>

          {/* Recommended Projects */}
          <div>
            <div style={{display:'flex',justifyContent:'space-between',alignItems:'center',marginBottom:'0.75rem'}}>
              <h2 style={{fontWeight:700,fontSize:'0.95rem',color:text}}>🎯 Recommended Projects</h2>
              <Link to="/projects" style={{fontSize:'0.78rem',color:'#6c63ff',fontWeight:600,textDecoration:'none'}}>All →</Link>
            </div>
            {projects.length===0 ? (
              <div style={{background:card,border:`1px solid ${border}`,borderRadius:12,padding:'2rem',textAlign:'center',color:sub,fontSize:'0.85rem'}}>No open projects yet</div>
            ) : projects.map(p=>(
              <div key={p._id} onClick={()=>navigate(`/projects/${p._id}`)} style={{background:card,border:`1px solid ${border}`,borderRadius:12,padding:'1rem',marginBottom:'0.6rem',cursor:'pointer'}}>
                <div style={{fontWeight:700,fontSize:'0.875rem',color:text,marginBottom:'0.25rem'}}>{p.title}</div>
                <div style={{fontSize:'0.75rem',color:muted,marginBottom:'0.5rem'}}>{p.faculty?.name}</div>
                <div style={{display:'flex',alignItems:'center',gap:'0.5rem'}}>
                  <div style={{flex:1,height:4,background:border,borderRadius:99,overflow:'hidden'}}>
                    <div style={{height:'100%',width:`${p.match}%`,background:p.match>=70?'#22c55e':p.match>=40?'#f59e0b':'#ef4444',borderRadius:99}} />
                  </div>
                  <span style={{fontSize:'0.7rem',color:muted,fontWeight:600,flexShrink:0}}>{p.match}% match</span>
                </div>
              </div>
            ))}
          </div>

          {/* Right column */}
          <div style={{display:'flex',flexDirection:'column',gap:'1rem'}}>

            {/* Accepted Projects */}
            <div style={{background:card,border:`1px solid ${border}`,borderRadius:12,padding:'1rem'}}>
              <h2 style={{fontWeight:700,fontSize:'0.9rem',color:text,marginBottom:'0.75rem'}}>✅ Accepted Projects</h2>
              {accepted.length===0 ? (
                <div style={{color:sub,fontSize:'0.8rem',textAlign:'center',padding:'1rem 0'}}>No accepted projects yet</div>
              ) : accepted.map(r=>(
                <div key={r._id} onClick={()=>navigate(`/projects/${r.project?._id}`)} style={{padding:'0.5rem 0',borderBottom:`1px solid ${border}`,cursor:'pointer',lastChild:{border:'none'}}}>
                  <div style={{fontWeight:600,fontSize:'0.8rem',color:text}}>{r.project?.title}</div>
                  <div style={{fontSize:'0.72rem',color:'#22c55e'}}>by {r.faculty?.name}</div>
                </div>
              ))}
            </div>

            {/* Quick links */}
            <div style={{background:card,border:`1px solid ${border}`,borderRadius:12,padding:'1rem'}}>
              <h2 style={{fontWeight:700,fontSize:'0.9rem',color:text,marginBottom:'0.75rem'}}>⚡ Quick Actions</h2>
              {[
                {icon:'🔍', label:'Browse Projects', link:'/projects'},
                {icon:'🏆', label:'Add Achievement', link:'/achievements'},
                {icon:'📄', label:'Build Resume',    link:'/resume'},
                {icon:'🤝', label:'Connections',     link:'/friends'},
                {icon:'🏅', label:'Leaderboard',     link:'/leaderboard'},
              ].map(a=>(
                <Link key={a.link} to={a.link} style={{display:'flex',alignItems:'center',gap:'0.6rem',padding:'0.5rem 0',textDecoration:'none',borderBottom:`1px solid ${border}`,color:text,fontSize:'0.82rem',fontWeight:500}}>
                  <span>{a.icon}</span><span>{a.label}</span>
                </Link>
              ))}
            </div>
          </div>
        </div>
      </div>
    </div>
  );
}
